import React, { useState, useEffect } from 'react';
import { getLiveStats } from '../services/api';

function LiveStats() {
  const [stats, setStats] = useState({
    cpu_usage: 0,
    memory_usage: 0,
    memory_used_gb: 0,
    memory_total_gb: 0,
    power_consumption: 0,
    co2_emissions: 0
  });
  const [showInfo, setShowInfo] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await getLiveStats();
        setStats(response.data);
      } catch (error) {
        console.error('Error fetching live stats:', error);
      }
    };

    fetchStats();
    const interval = setInterval(fetchStats, 1000);
    return () => clearInterval(interval);
  }, []);

  const infoText = {
    co2: "CO₂ emissions calculated based on real-time power consumption and regional carbon intensity (mg/s).",
    power: "Estimated power usage based on CPU TDP (65W) and current workload activity.",
    memory: "Live memory utilization showing absolute usage against total system capacity."
  };

  const InfoIcon = ({ type }) => (
    <span
      className="info-icon"
      onMouseEnter={() => setShowInfo(type)}
      onMouseLeave={() => setShowInfo(null)}
      style={{
        cursor: 'help',
        marginLeft: '10px',
        fontSize: '0.8rem',
        color: '#4CAF50',
        border: '1px solid #4CAF50',
        borderRadius: '50%',
        padding: '0 5px',
        display: 'inline-block',
        width: '18px',
        height: '18px',
        textAlign: 'center',
        lineHeight: '16px'
      }}
    >
      i
    </span>
  );

  const Tooltip = ({ text }) => (
    <div style={{
      position: 'absolute',
      backgroundColor: '#333',
      color: '#fff',
      padding: '8px',
      borderRadius: '4px',
      fontSize: '0.85rem',
      zIndex: 100,
      maxWidth: '220px',
      marginTop: '5px',
      boxShadow: '0 4px 10px rgba(0,0,0,0.3)',
      left: '20px'
    }}>
      {text}
    </div>
  );

  return (
    <div className="live-stats" style={{
      padding: '20px',
      backgroundColor: '#f9f9f9',
      borderRadius: '12px',
      boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
      margin: '20px 0'
    }}>
      <h2 style={{ color: '#2c3e50', marginBottom: '20px' }}>Real-Time System Monitoring</h2>

      <div className="stat-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px' }}>

        <div className="stat-item" style={{ position: 'relative', padding: '15px', background: '#fff', borderRadius: '8px', borderLeft: '4px solid #3498db' }}>
          <p style={{ margin: 0, color: '#7f8c8d', fontSize: '0.9rem' }}>CPU Usage</p>
          <p style={{ margin: '10px 0 0', fontSize: '1.5rem', fontWeight: 'bold' }}>{stats.cpu_usage}%</p>
        </div>

        <div className="stat-item" style={{ position: 'relative', padding: '15px', background: '#fff', borderRadius: '8px', borderLeft: '4px solid #e67e22' }}>
          <p style={{ margin: 0, color: '#7f8c8d', fontSize: '0.9rem' }}>
            Memory <InfoIcon type="memory" />
          </p>
          <p style={{ margin: '10px 0 0', fontSize: '1.1rem', fontWeight: 'bold' }}>
            {stats.memory_used_gb} / {stats.memory_total_gb} GB
          </p>
          <p style={{ margin: 0, fontSize: '0.8rem', color: '#95a5a6' }}>({stats.memory_usage}%)</p>
          {showInfo === 'memory' && <Tooltip text={infoText.memory} />}
        </div>

        <div className="stat-item" style={{ position: 'relative', padding: '15px', background: '#fff', borderRadius: '8px', borderLeft: '4px solid #f1c40f' }}>
          <p style={{ margin: 0, color: '#7f8c8d', fontSize: '0.9rem' }}>
            Power <InfoIcon type="power" />
          </p>
          <p style={{ margin: '10px 0 0', fontSize: '1.5rem', fontWeight: 'bold' }}>{stats.power_consumption} W</p>
          {showInfo === 'power' && <Tooltip text={infoText.power} />}
        </div>

        <div className="stat-item" style={{ position: 'relative', padding: '15px', background: '#fff', borderRadius: '8px', borderLeft: '4px solid #2ecc71' }}>
          <p style={{ margin: 0, color: '#7f8c8d', fontSize: '0.9rem' }}>
            CO₂ Emissions <InfoIcon type="co2" />
          </p>
          <p style={{ margin: '10px 0 0', fontSize: '1.5rem', fontWeight: 'bold', color: '#27ae60' }}>
            {stats.co2_emissions} <span style={{ fontSize: '0.9rem' }}>mg/s</span>
          </p>
          {showInfo === 'co2' && <Tooltip text={infoText.co2} />}
        </div>

      </div>
    </div>
  );
}

export default LiveStats;
